const items = $input.all();

function extractYouTubeVideoId(input) {
  if (!input || typeof input !== 'string') return null;

  const text = input.trim();

  const patterns = [
    /youtu\.be\/([a-zA-Z0-9_-]{11})/,
    /youtube\.com\/watch\?v=([a-zA-Z0-9_-]{11})/,
    /youtube\.com\/shorts\/([a-zA-Z0-9_-]{11})/,
    /youtube\.com\/embed\/([a-zA-Z0-9_-]{11})/,
    /(?:^|[^a-zA-Z0-9_-])([a-zA-Z0-9_-]{11})(?:$|[^a-zA-Z0-9_-])/
  ];

  for (const pattern of patterns) {
    const match = text.match(pattern);
    if (match?.[1]) return match[1];
  }

  return null;
}

return items.map(item => {
  const chatInput = item.json.message?.text || "";
  const videoId = extractYouTubeVideoId(chatInput);

  if (!videoId) {
    throw new Error(`Invalid YouTube source. video_id tidak ditemukan dari input: ${chatInput}`);
  }

  return {
    json: {
      source: `https://youtu.be/${videoId}`,
      video_id: videoId,
      original_input: chatInput
    }
  };
});
